var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그라운드 원에 발령된 심각한 뇌우 경보는 며칠 간 지속될 전망입니다.","JPN":"グラウンド・ワンに発令された深刻な雷雨警報は、数日続く見込みです。","ENG":"The severe thunderstorm warning issued for Ground One is anticipated to last several days.","TWN":"針對G1發布的豪雨特報預計將持續好幾天，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"현재, 관리국은 원인 불명의 기상 현상을 통제하는 데에 최선의 노력을 다하고 있으나…….","JPN":"現在、管理局は原因不明の気象現象を統制するために\\n最善を尽くしていますが……","ENG":"Currently, the Administration is exerting significant effort to control this unidentified weather phenomenon...","TWN":"目前管理局正全力控制不明原因的氣象異常現象，但是……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……라고 하니 다른 도리가 없군요.","JPN":"……ということですので、仕方ありませんね。","ENG":"...So they say, and there's nothing we can do about it.","TWN":"……所以，沒辦法。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회 및 각 교내 모임의 학생 대표 여러분.","JPN":"生徒会および校内会の学年代表の皆様。","ENG":"Student Council and club leaders.","TWN":"學生會和各位學生代表，"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"금일부터 사흘간 개최 예정이었던 아카데미 페스타는 현시간부로 중단하겠습니다.","JPN":"本日より3日間開催予定だったアカデミーフェスタは、\\n現時刻をもって中止いたします。","ENG":"The school festival that was scheduled for three days starting today is canceled, effective immediately.","TWN":"我宣布，從今天起為期三天的學園祭，立刻暫停舉辦。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"따라서 각 대표 여러분은 학급과 동아리로 돌아가셔서 이 사실을 공유해 주시기 바랍니다.","JPN":"従って、各代表の皆様は学級やサークルに戻り、この決定を共有してください。","ENG":"Therefore, each club leader should go back to their respective clubs and share this news with the others.","TWN":"請各位回去向班級和社團傳達這個消息。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 잠깐만요! 회장님!","JPN":"ま、待ってください！　会長！","ENG":"H-hold on! Ms. President!","TWN":"先，先等一下！會長！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"일 년에 딱 한 번 여는 페스타잖아요! 그런데 개최 당일에 중지 선언이라니요!?","JPN":"一年に一度のフェスタですよ！\\nなのに開催当日に中止宣言をするんですか！？","ENG":"This festival only happens once a year! How can you cancel it last minute last this?!","TWN":"這是一年一次的學園祭欸！怎麼可以在活動當天才喊停！？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카의 마음은 잘 알고 있어요. 총학생회장으로서 이런 결정을 내리게 되어 유감입니다.","JPN":"ミカさんの気持ちはよくわかります。\\n生徒会長として、このような決断を下したことはとても残念に思います。","ENG":"I understand your frustration, Mika. And I deliver this news with a heavy heart as the Student President.","TWN":"米卡，我明白你的心情。身為學生會會長，我也很遺憾做出這個決定。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 축제를 즐기려는 마음만큼, 학생분들의 안전도 매우 중요한 문제예요.","JPN":"しかし学園祭を楽しみたい気持ちと同じく、生徒たちの安全もとても重要です。","ENG":"But as much as I want all students to enjoy the festival, the safety of the student body is a crucial matter.","TWN":"只是學園祭的同樂固然重要，但學生們的安全考量也很重要。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"교직원분들 또한 이런 날씨에 페스타를 여는 것을 무척 염려하고 계시고요.","JPN":"教職員の方々も、\\nこのような天気でフェスタを開くことをとても心配しています。","ENG":"The faculty are also concerned about having a festival in this weather.","TWN":"老師們對於要在這種天氣舉辦學園祭也是感到非常擔心。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그렇지만 회장님도 알고 계시잖아요!","JPN":"で、でも会長だってご存知じゃないですか！？","ENG":"B-but Ms. President! You also know!","TWN":"可，可是，會長你也有看到不是嗎！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그동안 여기 있는 모두가 한 마음이 돼서 페스타를 준비해 왔다는 걸!","JPN":"ここにいる皆が一丸となってフェスタを準備してきたということを！","ENG":"Everyone here's been working their butts off to prepare for the festival!","TWN":"這段時間，大家一起努力準備學園祭！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"너도 뭐라고 좀 해 봐, 호진아!","JPN":"マユミちゃんも何か言ってよ！","ENG":"Hey, Hojin! Don't just stand there, say something!","TWN":"你也說幾句話啊，鎬眞！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으, 으응?","JPN":"う、うん？","ENG":"H-huh?","TWN":"呃，蛤？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그게…… 사실 우리 반은 군고구마 디저트 카페를 개점하려고 했거든.","JPN":"それが……\\n実はうちのクラスは焼き芋のデザートカフェをやることにしていたの。","ENG":"Well... Our class was planning on opening a roasted sweet potato dessert cafe.","TWN":"那個……其實我們班本來是準備要開烤地瓜咖啡廳的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"헤헤, 그런데 고구마 배송이 늦어진다고 해서 축제가 좀 더 미뤄져도 좋을 것 같아.","JPN":"でも雨でさつまいもの配送が遅れると言われて困っていたから、\\n学園祭が遅れてちょっと助かったかも、えヘヘッ。","ENG":"Heh, but it turns out that the delivery for our sweet potatoes got delayed. So I don't mind the festival getting pushed back a little.","TWN":"嘿嘿，但是地瓜來不及在時間內送到，所以延後幾天再辦好像也不錯。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 잠깐! 방금 회장님 이야기 못 들었어?","JPN":"ち、ちょっと待ってよ！　さっき会長の話を聞いたでしょ？","ENG":"W-wait! Didn't you hear what she just told us?","TWN":"喂，等等！你沒聽到剛會長說的嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이대로라면 페스타는 끝장이야. 곧 기말고사라 학교에서도 허락해 주지 않을 거라구.","JPN":"このままだとフェスタはおしまいだよ。\\nもうすぐ期末試験だから、アカデミー側が後日開催なんて許可するはずがないもの。","ENG":"At this rate, there is no festival. Plus, finals are just around the corner, so the school won't allow it.","TWN":"這樣的話學園祭就沒戲唱了，就快要到期末考了，學校也不可能會答應的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"사부, 그게 정말이에요?","JPN":"師匠、それは本当ですか？","ENG":"Master, is that true?","TWN":"師父，米卡說的是真的嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 아시다시피 올해는 아카데미에 다사다난한 한 해였죠.","JPN":"はい。\\nご存知のとおり、今年はアカデミーにとって多事多難な一年でした。","ENG":"I'm afraid so. As you all know, it has been a rough year at the Academy.","TWN":"是，你們也知道，今年學院真的是多災多難的一年。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};